import React, { PureComponent } from 'react';
import { Cell, Pie, PieChart, ResponsiveContainer, Tooltip } from 'recharts';
import './OperatingSystemsTile.local.scss';
import { OperatingSystemsConstants, OperatingSystemsForSelectedServer } from './OperatingSystemsConstants';
import { Overflow } from '../../../shared/components/layout';
import { OptionsList } from '../OptionsTile/components/OptionsList/OptionsList';
import { ChartTooltip } from '../ChartTooltip/ChartTooltip';

export default class OperatingSystemsTile extends PureComponent {
  render() {
    const { selectedServer } = this.props;
    const osPieData = selectedServer ? OperatingSystemsForSelectedServer.osData : OperatingSystemsConstants.osData;
    const serverEditionPieData = selectedServer ? OperatingSystemsForSelectedServer.serverEditionData : OperatingSystemsConstants.serverEditionData;
    const serverVersionsPieData = selectedServer ? OperatingSystemsForSelectedServer.serverVersionsData : OperatingSystemsConstants.serverVersionsData;

    return (
      <div className="exec-dashboard-graph-container operating-systems-graph-container">
        <div className="charts-container">
          <div className="chart">
            <div className="chart-title">Operating System</div>
            <div className="graph-legend-container">
              <Overflow>
                <OptionsList options={osPieData} />
              </Overflow>
            </div>
            <ResponsiveContainer height={380}>
              <PieChart>
                <Pie data={osPieData} dataKey="value" cx="50%" cy="60%" innerRadius={40} outerRadius={80} blendStroke>
                  {osPieData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Pie>
                <Tooltip content={ChartTooltip} />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="chart">
            <div className="chart-title">DB Edition</div>
            <div className="graph-legend-container">
              <Overflow>
                <OptionsList options={serverEditionPieData} />
              </Overflow>
            </div>
            <ResponsiveContainer height={380}>
              <PieChart>
                <Pie data={serverEditionPieData} dataKey="value" cx="50%" cy="60%" innerRadius={40} outerRadius={80} blendStroke>
                  {serverEditionPieData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Pie>
                <Tooltip content={ChartTooltip} />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="chart">
            <div className="chart-title">DB Version</div>
            <div className="graph-legend-container">
              <Overflow>
                <OptionsList options={serverVersionsPieData} />
              </Overflow>
            </div>
            <ResponsiveContainer height={380}>
              <PieChart>
                <Pie data={serverVersionsPieData} dataKey="value" cx="50%" cy="60%" innerRadius={40} outerRadius={80} blendStroke>
                  {serverVersionsPieData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Pie>
                <Tooltip content={ChartTooltip} />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    );
  }
}
